def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for idx, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        base_ratio = item / capacity
        score = 0.0
        for p in range(1, 20):
            inner_sum = 0
            for q in range(1, p+1):
                coef = ((-1)**(q) if q % 2 == 0 else 1) * (1/(q+0.5)) * (base_ratio ** q)
                inner_sum += coef
            score += inner_sum / (p**1.5)
        leftover = capacity - item
        if leftover <= 0.05 * capacity:
            score *= 3
        elif leftover <= 0.15 * capacity:
            score *= 1.8
        elif leftover <= 0.35 * capacity:
            score *= 1.3
        else:
            score *= 0.65
        mods = [2, 3, 5, 7, 11]
        mod_counts = sum([1 for m in mods if int(capacity) % m == 0])
        if mod_counts >= 3:
            score -= 0.4
        elif mod_counts == 2:
            score -= 0.25
        elif mod_counts == 1:
            score -= 0.1
        prime_factors = [2,3,5,7,11,13,17]
        penalty = 0
        for pf in prime_factors:
            if int(capacity) % pf == 0:
                penalty += (pf * 0.02)
        score -= penalty
        for factor_check in range(1, int(capacity)+1):
            if factor_check > item and factor_check % 4 == 0 and factor_check % 6 != 0:
                try:
                    score += np.sqrt(factor_check + base_ratio * 10) * 0.002
                except:
                    pass
            elif factor_check < item and factor_check % 3 == 0:
                score -= np.log1p(abs(factor_check - item)) * 0.001
        for mult in range(1, 6):
            val = item * mult
            if abs(capacity - val) < 0.04 * (capacity):
                score += 0.1 * mult
            else:
                score -= 0.02 * mult
        if score < 0:
            score = 0
        if score > 2:
            for div in range(2, 5):
                if abs((capacity / div) - item) < 0.015 * (capacity / div):
                    score *= (1 + 0.07 * div)
        if capacity > 50:
            for extra in range(1, 4):
                partial = (score / (extra + base_ratio)) - np.sin(base_ratio * extra)
                if partial > 0:
                    score += partial * 0.005
                else:
                    score += partial * 0.002
        priorities[idx] = score
    return priorities
